// ─── Geometric Shapes for Cards ──────────────────────────────────
const GeometricShapes = ({ variant = 0 }) => {
  const shapes = [
    // Variant 0: teal diagonal + purple square + yellow square
    <svg key="0" viewBox="0 0 200 200" style={{ position: "absolute", right: 0, top: 0, width: "45%", height: "100%", opacity: 0.9 }}>
      <rect x="20" y="-20" width="200" height="60" fill="#5B9E8F" transform="rotate(-25, 120, 10)" />
      <rect x="100" y="40" width="70" height="70" fill="#7B5EA7" />
      <rect x="90" y="100" width="60" height="60" fill="#E8A838" />
      <rect x="40" y="120" width="180" height="50" fill="#5B9E8F" transform="rotate(-25, 130, 145)" />
    </svg>,
    // Variant 1: similar pattern shifted
    <svg key="1" viewBox="0 0 200 200" style={{ position: "absolute", right: 0, top: 0, width: "45%", height: "100%", opacity: 0.9 }}>
      <rect x="20" y="-10" width="200" height="55" fill="#5B9E8F" transform="rotate(-25, 120, 15)" />
      <rect x="110" y="50" width="65" height="65" fill="#7B5EA7" />
      <rect x="80" y="105" width="55" height="55" fill="#E8A838" />
      <rect x="30" y="130" width="190" height="45" fill="#5B9E8F" transform="rotate(-25, 125, 152)" />
    </svg>,
    // Variant 2
    <svg key="2" viewBox="0 0 200 200" style={{ position: "absolute", right: 0, top: 0, width: "45%", height: "100%", opacity: 0.9 }}>
      <rect x="15" y="-15" width="210" height="55" fill="#5B9E8F" transform="rotate(-25, 120, 12)" />
      <rect x="105" y="45" width="68" height="68" fill="#7B5EA7" />
      <rect x="85" y="108" width="58" height="58" fill="#E8A838" />
      <rect x="25" y="125" width="195" height="48" fill="#5B9E8F" transform="rotate(-25, 122, 149)" />
    </svg>,
    // Variant 3
    <svg key="3" viewBox="0 0 200 200" style={{ position: "absolute", right: 0, top: 0, width: "45%", height: "100%", opacity: 0.9 }}>
      <rect x="25" y="-10" width="195" height="52" fill="#5B9E8F" transform="rotate(-25, 118, 16)" />
      <rect x="108" y="48" width="66" height="66" fill="#7B5EA7" />
      <rect x="88" y="110" width="56" height="56" fill="#E8A838" />
      <rect x="35" y="128" width="185" height="46" fill="#5B9E8F" transform="rotate(-25, 128, 151)" />
    </svg>,
  ];
  return shapes[variant % shapes.length];
};

// ─── Laptop Mockup ───────────────────────────────────────────────
const LaptopMockup = ({ title }) => (
  <div style={{ position: "relative", zIndex: 2, width: "65%", margin: "0 auto" }}>
    <div style={{
      background: "#fff",
      borderRadius: "8px 8px 0 0",
      border: "2px solid #ccc",
      overflow: "hidden",
      aspectRatio: "16/10",
    }}>
      {/* Browser chrome */}
      <div style={{
        background: "#E8E8E8",
        padding: "6px 12px",
        display: "flex",
        alignItems: "center",
        gap: "6px",
        borderBottom: "1px solid #ccc"
      }}>
        <div style={{ width: 8, height: 8, borderRadius: "50%", background: "#FF5F57" }} />
        <div style={{ width: 8, height: 8, borderRadius: "50%", background: "#FFBD2E" }} />
        <div style={{ width: 8, height: 8, borderRadius: "50%", background: "#28CA41" }} />
        <div style={{ flex: 1, background: "#fff", borderRadius: 4, height: 16, marginLeft: 8 }} />
      </div>
      {/* Screen content placeholder */}
      <div style={{ padding: "16px", background: "#fff" }}>
        <div style={{ fontSize: 11, color: "#333", fontFamily: "JetBrains Mono, monospace", fontWeight: 700 }}>{title}</div>
        <div style={{ marginTop: 8, display: "flex", gap: 8 }}>
          <div style={{ width: "30%", height: 6, background: "#e0e0e0", borderRadius: 3 }} />
          <div style={{ width: "20%", height: 6, background: "#e0e0e0", borderRadius: 3 }} />
        </div>
        <div style={{ marginTop: 12, display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
          {[1, 2, 3].map(i => (
            <div key={i} style={{ height: 40, background: "#f5f5f5", borderRadius: 4, border: "1px solid #eee" }} />
          ))}
        </div>
        <div style={{ marginTop: 10, height: 20, background: "#f0f0f0", borderRadius: 4 }} />
        <div style={{ marginTop: 6, height: 20, background: "#f8f8f8", borderRadius: 4 }} />
      </div>
    </div>
    {/* Laptop base */}
    <div style={{
      height: 12,
      background: "linear-gradient(to bottom, #C0C0C0, #A0A0A0)",
      borderRadius: "0 0 4px 4px",
      margin: "0 -5%",
    }} />
  </div>
);

// ─── Phone Mockup ────────────────────────────────────────────────
